using JSON

# Get directory of this file
dir = dirname(@__FILE__)

"""
	gen(domain, name)

Generate fixture data using Float32 `10^x` and write to file.
"""
function gen(domain, name)
	x = collect(domain)
	y = [10.0f0 ^ v for v in x]

	data = Dict([
		("x", x),
		("expected", y)
	])

	filepath = joinpath(dir, name)
	open(filepath, "w") do io
		write(io, JSON.json(data))
		write(io, "\n")
	end
end

# IEEE 754 safe float32 domain: -38.0 to +38.0
max_safe = Float32(38.0)
min_safe = Float32(-38.0)
epsilon54 = Float32(2.0)^-54

# Medium negative values: [-38.0, -1.0]
x = Float32.(range(min_safe, stop=-1.0f0, length=2003))
gen(x, "medium_negative.json")

# Medium positive values: [1.0, 38.0]
x = Float32.(range(1.0f0, stop=max_safe, length=2003))
gen(x, "medium_positive.json")

# Small negative values: [-1.0, -2^-54]
x = Float32.(range(-1.0f0, stop=-epsilon54, length=1007))
gen(x, "small_negative.json")

# Small positive values: [2^-54, 1.0]
x = Float32.(range(epsilon54, stop=1.0f0, length=1007))
gen(x, "small_positive.json")

# Tiny values: [-2^-54, 2^-54]
x = Float32.(range(-epsilon54, stop=epsilon54, length=1007))
gen(x, "tiny.json")
